mapper.delete:
DELETE
  FROM TOUR_WISH_TBL
 WHERE TOUR_WISHLIST_NO = #{tourWishlistNo}
   AND TOUR_ITEM_NO = #{tourItemNo}

mapper.select:
SELECT TOUR_WISHLIST_NO
  FROM TOUR_WISHLIST_TBL
 WHERE MEMBER_ID = #{memberId}
   AND TOUR_WISHLIST_NAME = #{tourWishlistName}

SELECT TOUR_WISHLIST_NO
  FROM TOUR_WISH_TBL
  JOIN TOUR_WISHLIST_TBL USING (TOUR_WISHLIST_NO)
 WHERE MEMBER_ID = #{memberId}
   AND TOUR_ITEM_NO = #{tourItemNo}

SELECT TOUR_ITEM_NO , TOUR_ITEM_NAME , TOUR_ITEM_ADULT_PRICE , TOUR_ITEM_KID_PRICE , START_PERIOD , END_PERIOD , TOUR_ITEM_DAYS , TOUR_ITEM_STATUS , (SELECT I.TOUR_ITEM_IMG_PATH FROM TOUR_ITEM_IMG_TBL I WHERE I.TOUR_ITEM_NO = T.TOUR_ITEM_NO AND I.TOUR_ITEM_IMG_ORDER = 1) AS TOUR_ITEM_IMG_PATH FROM TOUR_ITEM_TBL T
AND TOUR_ITEM_NAME LIKE '%' || #{searchWhere} || '%'
AND TOUR_ITEM_ADULT_PRICE >= #{searchPriceMin}
AND TOUR_ITEM_ADULT_PRICE <= #{searchPriceMax}
